FIRST-S00072.filter_expression:
/* GPResult match */
lower(commandLine) RLIKE '\bgpresult\b'
/* Get-DomainGPO via PowerView */
OR lower(commandLine) RLIKE '\bget-domaingpo\b'
/* Get-DomainGPOLocalGroup */
OR lower(commandLine) RLIKE '\bget-domaingpolocalgroup'
/* WinPwn GPORemoteAccessPolicy */
OR lower(commandLine) RLIKE '\bgpoaudit\b\s-noninteractive\s-consoleoutput'
OR lower(commandLine) RLIKE '\bgporemoteaccesspolicy\b\s-consoleoutput\s-noninteractive'
/* Get-GPO cmdlet */
OR lower(commandLine) RLIKE '\bget-gpo\b'

MATCH-S00319.expression:
(
    lower(commandLine) like '%\svchost.exe c:\users\%\desktop\%' OR
    (
        lower(baseImage) like '%\svchost.exe' AND
        (
            lower(commandLine) like '%whoami.exe /all' OR
            lower(commandLine) like '%net.exe view'
        )
    )
)

